function c(t){const r=Date.now()-t,o=Math.abs(r),n=r>=0?"ago":"from now",e=Math.round(o/1e3);if(e<60)return`${e}s ${n}`;const a=Math.round(e/60);if(a<60)return`${a}m ${n}`;const u=Math.round(a/60);if(u<24)return`${u}h ${n}`;const i=Math.round(u/24);if(i<30)return`${i}d ${n}`;const m=Math.round(i/30);return m<12?`${m}mo ${n}`:`${Math.round(m/12)}y ${n}`}const f=new Intl.DateTimeFormat("en-US",{year:"numeric",month:"short",day:"numeric",hour:"2-digit",minute:"2-digit",second:"2-digit"});function s(t){return f.format(new Date(t))}function d(t){return new Intl.DateTimeFormat("en-US",{year:"numeric",month:"short",day:"numeric"}).format(new Date(t))}function h(t){return new Intl.NumberFormat("en-US").format(t)}function $(t){return new Intl.NumberFormat("en-US",{notation:"compact",maximumFractionDigits:1}).format(t)}function M(t){if(t<1e3)return`${Math.round(t)}ms`;const r=t/1e3;if(r<60)return`${r.toFixed(1)}s`;const o=Math.floor(r/60),n=Math.round(r%60);return o<60?`${o}m ${n}s`:`${Math.floor(o/60)}h ${o%60}m`}function F(t){return t>=1e3?`${(t/1e3).toFixed(2)}s`:`${Math.round(t)}ms`}function l(t){return t<1024?`${t} B`:t<1024*1024?`${(t/1024).toFixed(1)} KB`:`${(t/(1024*1024)).toFixed(2)} MB`}export{F as a,s as b,c,M as d,l as e,$ as f,h as g,d as h};
